def divSum(n):
    # Initialize result
    result = 1

    # Find all divisors and add them
    i = 2
    while(i * i <= n):
        if (n % i == 0):
            if (i * i != n):
                result += i + n // i
            else:
                result += i
        i += 1

    # Return the sum of divisors
    return result

