def get_total_number_of_sequences(n, m):
    # Initialize a 2D list (dp) with zeros
    dp = [[0 for _ in range(m + 1)] for _ in range(n + 1)]

    # Base case: There's one way to form a sequence of length 1 with any number from 1 to m
    for i in range(1, m + 1):
        dp[1][i] = 1

    # Fill the dp table
    for i in range(2, n + 1):
        for j in range(1, m + 1):
            dp[i][j] = sum(dp[i-1][k] for k in range(j//2, j+1))

    # The answer is the sum of all possible sequences of length n with any number from 1 to m
    return sum(dp[n][i] for i in range(1, m + 1))

