def max_sum(arr):
    n = len(arr)

    # Create arrays to store the maximum sum increasing subsequence ending at each index and decreasing subsequence starting at each index
    inc = arr[:]
    dec = [0] * n

    # Compute maximum sum increasing subsequence for each element
    for i in range(1, n):
        for j in range(i):
            if arr[i] > arr[j] and inc[i] < inc[j] + arr[i]:
                inc[i] = inc[j] + arr[i]

    # Compute maximum sum decreasing subsequence for each element
    dec[n-1] = arr[n-1]
    for i in range(n-2, -1, -1):
        for j in range(i+1, n):
            if arr[i] > arr[j] and dec[i] < dec[j] + arr[i]:
                dec[i] = dec[j] + arr[i]

    # Compute the maximum sum bi-tonic subsequence
    max_sum = 0
    for i in range(n):
        max_sum = max(max_sum, inc[i] + dec[i] - arr[i])

    return max_sum

