                return False
        return True

    def nsw_number(k):
        if k == 0 or k == 1:
            return 1
        return (nsw_number(k - 1) * (2 * k - 1)) + nsw_number(k - 2)

    count = 0
    num = 2
    while True:
        if is_prime(nsw_number(num)):
            count += 1
            if count == n:
