def longest_increasing_subsequence(sequence):
    if not sequence:
        return 0

    # Initialize the list to store the length of the longest subsequence ending at each index
    lis = [1] * len(sequence)

    # Compute the LIS values in a bottom-up manner
    for i in range(1, len(sequence)):
        for j in range(i):
            if sequence[i] > sequence[j]:
                lis[i] = max(lis[i], lis[j] + 1)

    # The length of the longest increasing subsequence is the maximum value in lis
    return max(lis)

def Total_Hamming_Distance(n):
    total_distance = 0
    for i in range(n + 1):
        for j in range(i + 1, n + 1):
            xor_result = i ^ j
            while xor_result:
                total_distance += xor_result & 1
                xor_result >>= 1
    return total_distance

