def find_kth(arr1, arr2, k):
    if len(arr1) > len(arr2):
        return find_kth(arr2, arr1, k)

    if not arr1:
        return arr2[k]

    if k == 0:
        return min(arr1[0], arr2[0])

    i = min(k // 2, len(arr1) - 1)
    j = min(k // 2, len(arr2) - 1)

    if arr1[i] > arr2[j]:
        return find_kth(arr1, arr2[j+1:], k-j-1)
    else:
        return find_kth(arr1[i+1:], arr2, k-i-1)

def min_Swaps(s1, s2):
    # Check if lengths are equal
    if len(s1) != len(s2):
        return -1

    n = len(s1)
    count_0s_s1 = 0
    count_1s_s1 = 0
    count_0s_s2 = 0
    count_1s_s2 = 0

    # Count the number of 0s and 1s in both strings
    for i in range(n):
        if s1[i] == '0':
            count_0s_s1 += 1
        else:
            count_1s_s1 += 1

        if s2[i] == '0':
            count_0s_s2 += 1
        else:
            count_1s_s2 += 1

    # If the counts of 0s and 1s are not equal, return -1
    if (count_0s_s1 != count_0s_s2) or (count_1s_s1 != count_1s_s2):
        return -1

    # Calculate the number of misplaced swaps needed
    misplaced = 0
    for i in range(n):
        if s1[i] != s2[i]:
            misplaced += 1

    # Each pair of misplaced positions requires one swap
    return misplaced // 2

