def min_Swaps(s1, s2):
    # Check if both strings are of equal length
    if len(s1) != len(s2):
        return -1

    # Initialize count of differing bits and positions of '0's in s1
    diff_count = 0
    zero_positions = []

    # Iterate through the strings to find differing bits and positions of '0's
    for i in range(len(s1)):
        if s1[i] != s2[i]:
            diff_count += 1
            if s1[i] == '0':
                zero_positions.append(i)

    # If the number of differing bits is odd, it's not possible to make them equal
    if diff_count % 2 != 0:
        return -1

    # Initialize swap count
    swap_count = 0

    # Iterate through pairs of '0's and calculate swaps needed
    for i in range(0, len(zero_positions), 2):
        if zero_positions[i] + 1 == zero_positions[i + 1]:
            continue
        else:
            swap_count += 1

    return swap_count

