def find_first_occurrence(arr, target):
    left, right = 0, len(arr) - 1
    result = -1

    while left <= right:
        mid = (left + right) // 2

        if arr[mid] == target:
            result = mid
            right = mid - 1  # Continue to search in the left half
        elif arr[mid] < target:
            left = mid + 1
        else:
            right = mid - 1

    return result

