def find_Sum(arr):
    # Create a dictionary to store the frequency of each element
    freq = {}
    for num in arr:
        if num in freq:
            freq[num] += 1
        else:
            freq[num] = 1

    # Calculate the sum of non-repeated elements
    non_repeated_sum = 0
    for num, count in freq.items():
        if count == 1:
            non_repeated_sum += num

    return non_repeated_sum

