def get_Number(arr, k):
    # Filter out odd and even numbers into separate lists
    odd_numbers = [num for num in arr if num % 2 != 0]
    even_numbers = [num for num in arr if num % 2 == 0]

    # Check if k is within the bounds of the combined list
    if k <= len(odd_numbers):
        return odd_numbers[k - 1]
    elif k <= len(odd_numbers) + len(even_numbers):
        return even_numbers[k - len(odd_numbers) - 1]
    else:
        raise IndexError("k is out of bounds")

