def find_Min_Swaps(binary_array):
    n = len(binary_array)
    swaps = 0
    i = 0

    while i < n:
        if binary_array[i] == 1:
            j = i + 1
            while j < n and binary_array[j] != 0:
                j += 1

            if j < n:
                # Swap the found 0 with the current 1
                binary_array[i], binary_array[j] = binary_array[j], binary_array[i]
                swaps += (j - i)
                i += 2
            else:
                break
        else:
            i += 1

    return swaps

