def super_seq(str1, str2):
    m = len(str1)
    n = len(str2)

    # Create a 2D array to store lengths of longest common subsequence.
    dp = [[0] * (n + 1) for _ in range(m + 1)]

    # Build the dp array from bottom up
    for i in range(1, m + 1):
        for j in range(1, n + 1):
            if str1[i - 1] == str2[j - 1]:
                dp[i][j] = dp[i - 1][j - 1] + 1
            else:
                dp[i][j] = max(dp[i - 1][j], dp[i][j - 1])

    # The length of the shortest supersequence is m + n - length of LCS
    return m + n - dp[m][n]

def count_tuplex(tuplex):
    # Create an empty dictionary to store item counts
    item_count = {}

    # Iterate over each item in the tuple
    for item in tuplex:
        # If the item is already in the dictionary, increment its count
        if item in item_count:
            item_count[item] += 1
        # Otherwise, add the item to the dictionary with a count of 1
        else:
            item_count[item] = 1

    return item_count

