def max_sum(arr):
    n = len(arr)
    # Create arrays to store the maximum sum of increasing subsequence ending at each index and decreasing subsequence starting at each index
    inc = [0] * n
    dec = [0] * n

    # Initialize both arrays with the elements of the input array
    for i in range(n):
        inc[i] = arr[i]
        dec[i] = arr[i]

    # Compute maximum sum of increasing subsequence ending at each index
    for i in range(1, n):
        for j in range(i):
            if arr[i] > arr[j] and inc[i] < inc[j] + arr[i]:
                inc[i] = inc[j] + arr[i]

    # Compute maximum sum of decreasing subsequence starting at each index
    for i in range(n-2, -1, -1):
        for j in range(i+1, n):
            if arr[i] > arr[j] and dec[i] < dec[j] + arr[i]:
                dec[i] = dec[j] + arr[i]

    # Compute the maximum sum of bi-tonic subsequence
    max_sum_biotonic = 0
    for i in range(n):
