        if num <= 1:
            return False
        if num <= 3:
            return True
        if num % 2 == 0 or num % 3 == 0:
            return False
        i = 5
        while i * i <= num:
            if num % i == 0 or num % (i + 2) == 0:
                return False
            i += 6
        return True

    def newman_shanks_williams(num):
        if num == 1:
            return 2
        if num == 2:
            return 3
        return (newman_shanks_williams(num - 1) ** 2 + 1) // newman_shanks_williams(num - 2)

    count = 0
    i = 1
    while True:
        ns_w_value = newman_shanks_williams(i)
        if is_prime(ns_w_value):
            count += 1
            if count == n:
                return ns_w_value
        i += 1

