def right_rotate(arr, n):
    i = 0
    while i < n:
        if (i % 2 == 0 and arr[i] < 0) or (i % 2 != 0 and arr[i] >= 0):
            j = i + 1
            while j < n and ((arr[j] < 0 and i % 2 == 0) or (arr[j] >= 0 and i % 2 != 0)):
                j += 1
            if j < n:
                arr[i], arr[j] = arr[j], arr[i]
        i += 1
    return arr

