def find_Divisor(start, end):
    divisor_count = {}

    for num in range(start, end + 1):
        for i in range(2, num + 1):
            if num % i == 0:
                if i in divisor_count:
                    divisor_count[i] += 1
                else:
                    divisor_count[i] = 1

    if not divisor_count:
        return None

    max_divisor = max(divisor_count, key=divisor_count.get)
    return max_divisor

