            min_value = min(min_value, item)  # Update min_value if current item is smaller

    return min_value if min_value != float('inf') else None  # Return None if no numbers were found

def rearrange_bigger(n):
    digits = list(str(n))
    for i in range(len(digits)-2, -1, -1):
        if digits[i] < digits[i+1]:
            right_part = digits[i:]
            min_greater_digit = min(filter(lambda x: x > right_part[0], right_part))
            right_part.remove(min_greater_digit)
            right_part.sort()
            digits[i:] = [min_greater_digit] + right_part
            return int("".join(digits))
    return False

