def breakSum(n, memo={}):
    if n in memo:
        return memo[n]
    if n <= 1:
        return n

    max_sum = max(breakSum(n//2, memo) + breakSum(n//3, memo) + breakSum(n//4, memo), n)
    memo[n] = max_sum
    return max_sum

