def max_profit(prices, k):
    n = len(prices)
    if n == 0:
        return 0

    # Create a table to store results of subproblems
    profit = [[0 for _ in range(n)] for _ in range(k + 1)]

    # Fill the table in bottom-up fashion
    for i in range(1, k + 1):
        max_diff = -prices[0]
        for j in range(1, n):
            profit[i][j] = max(profit[i][j-1], prices[j] + max_diff)
            max_diff = max(max_diff, profit[i-1][j] - prices[j])

    return profit[k][n-1]

def find_peak_util(arr, low, high, n):
    mid = low + (high - low) // 2

    # Check if mid is a peak
    if ((mid == 0 or arr[mid - 1] <= arr[mid]) and
        (mid == n - 1 or arr[mid + 1] <= arr[mid])):
        return mid

    # If the left neighbor is greater, then there must be a peak in the left half
    elif mid > 0 and arr[mid - 1] > arr[mid]:
        return find_peak_util(arr, low, (mid - 1), n)

    # Else, there must be a peak in the right half
    else:
        return find_peak_util(arr, (mid + 1), high, n)

