    lis = [1] * n
    lrs = [1] * n

    # Compute LIS values from left to right
    for i in range(1, n):
        for j in range(i):
            if arr[i] > arr[j] and lis[i] < lis[j] + 1:
                lis[i] = lis[j] + 1

    # Compute LRS values from right to left
    for i in range(n-2, -1, -1):
        for j in range(i+1, n):
            if arr[i] > arr[j] and lrs[i] < lrs[j] + 1:
                lrs[i] = lrs[j] + 1

    # Find the maximum value of lis[i] + lrs[i] - 1
