def min_Swaps(s1, s2):
    # If lengths of two strings are not same, then we can't make them equal
    if len(s1) != len(s2):
        return -1

    # To store count of '0's and '1's in string s1
    count_0 = 0
    count_1 = 0

    # Traverse through all characters of s1 and count '0's and '1's
    for i in range(len(s1)):
        if s1[i] == '0':
            count_0 += 1
        else:
            count_1 += 1

    # If counts of '0's and '1's are not same, then we can't make them equal
    if count_0 != count_1:
        return -1

    # To store the number of swaps required
    swap_count = 0

    # Traverse through all characters of s1 again
    for i in range(len(s1)):
        # If current character is '0' and next character is '1', then we need to swap
        if s1[i] == '0' and s2[i] == '1':
            j = i + 1
            # Find the next '1' in s1
            while j < len(s1) and s1[j] != '1':
                j += 1

            # If we found a '1', then swap it with current '0'
            if j < len(s1):
                s1 = s1[:i] + '1' + s1[i+1:j] + '0' + s1[j+1:]
                swap_count += 1

    return swap_count

