def min_Swaps(s1, s2):
    # If lengths of two strings are not same, return -1
    if len(s1) != len(s2):
        return -1

    # To store positions where characters differ
    diff = []

    # Find all the positions where characters in the two strings differ
    for i in range(len(s1)):
        if s1[i] != s2[i]:
            diff.append(i)

    # If there are no differences, no swaps needed
    if len(diff) == 0:
        return 0

    # If there is an odd number of differences, it's impossible to make the strings equal
    if len(diff) % 2 != 0:
        return -1

    # Calculate the minimum number of swaps required
    swaps = 0
    for i in range(0, len(diff), 2):
        if s1[diff[i]] != s2[diff[i+1]]:
            diff[i], diff[i+1] = diff[i+1], diff[i]
            swaps += 1

    return swaps

