def maximum_segments(n, a, b, c):
    # Initialize a list to store the maximum number of segments that can be formed up to each length
    dp = [0] * (n + 1)

    # Iterate through each possible length from 1 to n
    for i in range(1, n + 1):
        # Check if we can form a segment of length 'a' at the current length
        if i >= a:
            dp[i] = max(dp[i], dp[i - a] + 1)
        # Check if we can form a segment of length 'b' at the current length
        if i >= b:
            dp[i] = max(dp[i], dp[i - b] + 1)
        # Check if we can form a segment of length 'c' at the current length
        if i >= c:
            dp[i] = max(dp[i], dp[i - c] + 1)

    # The maximum number of segments that can be formed for length 'n' is stored in dp[n]
    return dp[n]

