    # Calculate the sum of the first row to use as a reference
    target_sum = sum(square[0])

    # Check the sums of all rows
    for row in square:
        if sum(row) != target_sum:
            return False

    # Check the sums of all columns
    for col in range(n):
        if sum(square[row][col] for row in range(n)) != target_sum:
            return False

    # Check the sum of the main diagonal
    if sum(square[i][i] for i in range(n)) != target_sum:
