    while i < n:
        if arr[i] >= 0 and (i % 2 == 1 or i == 0):
            j = i + 1
            while j < n and arr[j] >= 0:
                j += 1
            if j < n:
                temp = arr[j]
                for k in range(j, i, -1):
                    arr[k] = arr[k - 1]
                arr[i] = temp
        elif arr[i] < 0 and (i % 2 == 0 or i == 1):
            j = i + 1
            while j < n and arr[j] < 0:
                j += 1
            if j < n:
                temp = arr[j]
                for k in range(j, i, -1):
                    arr[k] = arr[k - 1]
                arr[i] = temp
        i += 1
    return arr

