    if not mine or rows == 0 or cols == 0:
        return 0

    dp = [[0] * cols for _ in range(rows)]

    for col in range(cols-1, -1, -1):
        for row in range(rows):
            right = dp[row][col+1] if col < cols - 1 else 0
            right_up = dp[row-1][col+1] if row > 0 and col < cols - 1 else 0
            right_down = dp[row+1][col+1] if row < rows - 1 and col < cols - 1 else 0

            dp[row][col] = mine[row][col] + max(right, right_up, right_down)

    return max(dp[row][0] for row in range(rows))

