def find_Max(arr, low, high):
    if low > high:
        return None

    mid = (low + high) // 2

    # Check if mid element is the maximum
    if (mid == 0 or arr[mid] > arr[mid - 1]) and \
       (mid == len(arr) - 1 or arr[mid] > arr[mid + 1]):
        return arr[mid]

    # Decide whether to go left or right
    if arr[low] < arr[mid]:
        return find_Max(arr, mid + 1, high)
    else:
        return find_Max(arr, low, mid - 1)

