def matrix_to_list(matrix):
    # Initialize an empty list to store the columns
    column_list = []

    # Iterate over each row in the matrix
    for row in matrix:
        # Iterate over each tuple in the row
        for i, value in enumerate(row):
            # If the column index is out of bounds, append a new tuple
            if len(column_list) <= i:
                column_list.append(value)
            else:
                # Otherwise, extend the existing tuple with the new value
                column_list[i] += value

    # Convert each tuple to a string and join them with commas
    result = ','.join(str(col) for col in column_list)

    return result

