def find_max_val(x, y):
    # The largest k such that k % x == y is (x - y) + x * n where n is a non-negative integer.
    # To maximize k, we choose the largest possible n which is floor((x - y) / x).
    # However, if y is 0, then the largest k is simply x itself.
    if y == 0:
        return x
    else:
        return (x - y) + x * ((x - y) // x)

def max_sum_of_three_consecutive(arr):
    n = len(arr)
    if n == 0:
        return 0
    elif n == 1:
        return arr[0]
    elif n == 2:
        return arr[0] + arr[1]

    dp = [0] * n
    dp[0] = arr[0]
    dp[1] = arr[0] + arr[1]
    dp[2] = max(arr[0] + arr[1], arr[0] + arr[2], arr[1] + arr[2])

    for i in range(3, n):
        dp[i] = max(dp[i-1], dp[i-2] + arr[i], dp[i-3] + arr[i])

    return dp[n-1]

