def maxAverageOfPath(matrix):
    n = len(matrix)
    if n == 0:
        return 0

    # Initialize a DP table to store maximum average up to each cell
    dp = [[0] * n for _ in range(n)]

    # Fill the DP table
    for i in range(n):
        for j in range(n):
            if i == 0 and j == 0:
                dp[i][j] = matrix[0][0]
            elif i == 0:
                dp[i][j] = max(dp[i][j-1], matrix[i][j])
            elif j == 0:
                dp[i][j] = max(dp[i-1][j], matrix[i][j])
            else:
                dp[i][j] = max(dp[i-1][j], dp[i][j-1]) + matrix[i][j]

    # The maximum average is the value in the bottom-right corner divided by n
    return dp[n-1][n-1] / n

