from itertools import groupby

def count_duplic(lst):
    if not lst:
        return ([], [])

    # Group consecutive duplicates and count their frequency
    grouped = [(len(list(group)), key) for key, group in groupby(lst)]

    # Separate the counts and keys into two lists
    counts = [count for count, _ in grouped]
    keys = [key for _, key in grouped]

    return (counts, keys)

