def nth_super_ugly_number(n, primes):
    ugly_numbers = [1]
    prime_indices = [0] * len(primes)

    while len(ugly_numbers) < n:
        next_ugly = min(primes[i] * ugly_numbers[prime_indices[i]] for i in range(len(primes)))
        ugly_numbers.append(next_ugly)

        for i in range(len(primes)):
            if primes[i] * ugly_numbers[prime_indices[i]] == next_ugly:
                prime_indices[i] += 1

    return ugly_numbers[-1]

def Check_Solution(a, b, c):
    # Calculate the discriminant
    discriminant = b**2 - 4*a*c

    # Check if the roots are real and distinct
    if discriminant > 0:
        root1 = (-b + discriminant**0.5) / (2*a)
        root2 = (-b - discriminant**0.5) / (2*a)

        # Check if the roots are numerically equal but opposite in sign
        if root1 == -root2:
            return "Yes"
        else:
            return "No"
    else:
        return "No"

