def min_Swaps(s1, s2):
    # If lengths of two strings are not same, we can't make them equal
    if len(s1) != len(s2):
        return -1

    # Count number of differing positions
    diff_count = 0
    for i in range(len(s1)):
        if s1[i] != s2[i]:
            diff_count += 1

    # If the number of differing positions is odd, we can't make them equal by swapping
    if diff_count % 2 != 0:
        return -1

    # Otherwise, the minimum swaps required will be half of the differing positions
    return diff_count // 2

