def find_Min_Swaps(arr):
    n = len(arr)
    swaps = 0
    i = 0
    while i < n:
        if arr[i] == 1 and i % 2 == 0:
            j = i + 1
            while j < n and arr[j] == 0:
                j += 1
            if j == n:
                return -1
            for k in range(j, i, -1):
                arr[k], arr[k-1] = arr[k-1], arr[k]
                swaps += 1
        i += 2
    return swaps

