def is_Isomorphic(str1, str2):
    if len(str1) != len(str2):
        return False

    char_map = {}
    mapped_chars = set()

    for char1, char2 in zip(str1, str2):
        if char1 in char_map:
            if char_map[char1] != char2:
                return False
        else:
            if char2 in mapped_chars:
                return False
            char_map[char1] = char2
            mapped_chars.add(char2)

    return True

