def find_Extra(arr1, arr2):
    left, right = 0, len(arr1) - 1

    while left <= right:
        mid = (left + right) // 2

        # If the middle element is not present in arr2 or if it is present but the next element is different
        if (mid == 0 or arr1[mid] != arr2[mid]) and (mid == len(arr1) - 1 or arr1[mid] != arr2[mid + 1]):
