def factorial(n):
    if n == 0 or n == 1:
        return 1
    else:
        return n * factorial(n - 1)

def sum_of_squares(n):
    total = 0
    for k in range(n + 1):
        binomial_coefficient = factorial(n) // (factorial(k) * factorial(n - k))
        total += binomial_coefficient ** 2
    return total

