def is_Two_Alter(s):
    if len(s) < 2:
        return False
    char1 = s[0]
    char2 = s[1]
    if char1 == char2:
        return False
    for i in range(2, len(s)):
        if s[i] != char1 and s[i] != char2:
            return False
        if s[i] == char1:
            char1, char2 = char2, char1
        else:
            char1, char2 = char2, char1
    return True

