    if n == 0 and m == 0:
        return 1
    if n == 0 or m == 0:
        return 0
    return (2 * (n + m - 1) * binomial_coeff(n + m - 2, n - 1)) // (n + m)

def check_date(day, month, year):
    if month < 1 or month > 12:
        return False
    if day < 1:
        return False
    if month == 2:
        if (year % 4 == 0 and year % 100 != 0) or (year % 400 == 0):
            if day > 29:
                return False
        else:
            if day > 28:
                return False
    elif month in [4, 6, 9, 11]:
        if day > 30:
            return False
    else:
        if day > 31:
            return False
    return True

def find_triplet_array(arr, n, sum):
    arr.sort()
    for i in range(0, n-2):
        l = i + 1
        r = n - 1
        while (l < r):
            if (arr[i] + arr[l] + arr[r] == sum):
                return True
            elif (arr[i] + arr[l] + arr[r] < sum):
                l += 1
            else:
                r -= 1
    return False

