def max_product(arr):
    if len(arr) < 2:
        raise ValueError("Array must contain at least two elements")

    arr.sort()
    n = len(arr)
    return (arr[n-1], arr[n-2])

def binomial_coeffi(n, k):
    if k > n:
        return 0
    if k == 0 or k == n:
        return 1
    return binomial_coeffi(n-1, k-1) + binomial_coeffi(n-1, k)

def rencontres_number(n, k):
    if k == 0:
        return 1
    return sum(binomial_coeffi(n-i, i) * (-1)**i for i in range(1, k+1))

class Node:
    def __init__(self, value):
        self.value = value
        self.left = None
        self.right = None

def height_of_binary_tree(node):
    if node is None:
        return 0
    else:
        left_height = height_of_binary_tree(node.left)
        right_height = height_of_binary_tree(node.right)
        return max(left_height, right_height) + 1

