import heapq

def combine_lists(list1, list2):
    return list(heapq.merge(list1, list2))

def re_arrange_tuples(tuples_list, order_list):
    # Create a dictionary to map each element in order_list to its index
    order_dict = {value: idx for idx, value in enumerate(order_list)}

    # Sort the tuples based on the index of their first element in the order_dict
    sorted_tuples = sorted(tuples_list, key=lambda x: order_dict[x[0]])

    return sorted_tuples

