def subset(nums):
    # Convert the list to a set to remove duplicates and then back to a list
    unique_nums = list(set(nums))
    # The number of subsets with distinct elements is equal to the length of the unique list
    return len(unique_nums)

import re

def split_list(input_string):
    return re.findall('[A-Z][^A-Z]*', input_string)

def nCr_mod_p(n, r, p):
    if r > n:
        return 0

    # Initialize an array to store intermediate results
    C = [0] * (r + 1)
    C[0] = 1  # nC0 is always 1

    for i in range(1, n + 1):
        # Compute values from the end to avoid overwriting
        for j in range(min(i, r), 0, -1):
            C[j] = (C[j] + C[j - 1]) % p

    return C[r]

def profit_amount(amount, cost):
    if amount > cost:
        return amount - cost
    else:
