def get_First_Set_Bit_Pos(n):
    if n == 0:
        return -1
    pos = 0
    while (n & 1) == 0:
        n >>= 1
        pos += 1
    return pos + 1

def roman_to_int(s: str) -> int:
    roman_map = {
        'I': 1,
        'V': 5,
        'X': 10,
        'L': 50,
        'C': 100,
        'D': 500,
        'M': 1000
    }

    total = 0
    prev_value = 0

    for char in reversed(s):
        value = roman_map[char]
        if value < prev_value:
            total -= value
        else:
            total += value
        prev_value = value

    return total

