def get_noOfways(n):
    if n == 0:
        return 1
    elif n == 1:
        return 1
    else:
        return get_noOfways(n-1) + get_noOfways(n-2)

def join_tuples(tuples_list):
    result = []
    for tup in tuples_list:
        if not result or tup[0] != result[-1][0]:
            result.append(tup)
        else:
            result[-1] += tup[1:]
    return result

def sum_Natural(l, r):
    total = 0
    for num in range(l, r + 1):
        if num % 2 == 0:
            total += num
    return total

def discriminant_value(a, b, c):
    discriminant = b**2 - 4*a*c
    if discriminant > 0:
        return ("two real solutions", discriminant)
    elif discriminant == 0:
        return ("one real solution", discriminant)
    else:
        return ("no real solution", discriminant)

